COMMENT ON COLUMN "strategy_scenarios"."sim_outputs_json" IS 'JSONB. Simulation outputs in JSON format. Example: {delta_ms:-2200}.';
COMMENT ON COLUMN "circuit_details"."circuit_ops_perf_compendium" IS 'JSONB column. Bundles lap-record info, circuit layout, pit operations, capacity, safety/surface, operational environment, media/hospitality, and certification/heritage for a quick operational/performance view of a circuit.  Nested fields: {"HeritageCertPack": {"FIA_GRADE": "TEXT. FIA homologation grade of the circuit. Possible values: Grade 1, Grade 2, Grade 3. Example: Grade 1.", "FirstGPYear": "BIGINT. First year a Grand Prix (or equivalent top series) was held at the circuit. Range: 1950–2025. Example: 2001."}, "LapRecordPack": {"LapRecordDriverRef": "TEXT. Driver reference (lowercase slug) for the official lap record holder. Possible values (observed): hamilton, schumacher, senna, verstappen. **NULL means no official lap record is available/confirmed (e.g., new circuit or not recorded).** Example: hamilton.", "LAP_RECORD_TIME": "TEXT. Lap record time formatted as M:SS.mmm. **NULL means the circuit has no official lap record time recorded/confirmed.** Example: 1:15.228.", "lapRecord_msec": "BIGINT. Lap record time in milliseconds. **NULL means lap record duration is not recorded/known.** Example: 74572.", "LapRecordYear": "BIGINT. Year when the lap record was set. **NULL means the lap record year is unknown or no record exists yet.** Example: 2023."}, "LayoutPack": {"track_length_KM": "REAL. Full lap length of the circuit in kilometers. Example: 5.412.", "NumberOfTurns": "BIGINT. Count of distinct turns. Example: 20.", "LONGEST_STRAIGHT_M": "REAL. Length of the longest straight in meters. Example: 1060.0.", "DRS_ZONES": "BIGINT. Count of DRS activation zones. Typical values: 1, 2, 3. Example: 2."}, "PitOpsPack": {"PitLaneLength_m": "REAL. Pit lane length in meters. Example: 420.0.", "PIT_LANE_SPEED_KPH": "REAL. Pit lane speed limit in kilometers per hour. Typical values: 60.0, 80.0, 100.0. Example: 80.0.", "GaragesCount": "BIGINT. Number of pit garages available. Example: 24."}, "CapacityPack": {"CapacityTOTAL": "BIGINT. Total spectator capacity. Example: 120000.", "Capacity_Grandstands": "BIGINT. Seated grandstand capacity. Example: 80000.", "capacity_general": "BIGINT. General admission capacity. Example: 40000."}, "SurfaceSafetyPack": {"SurfaceMaterial": "TEXT. Primary track surface. Possible values: asphalt, concrete. Example: asphalt.", "SurfaceLastResurfacedYear": "BIGINT. Last resurfacing year. Example: 2020.", "typicalGripLevel": "TEXT. Qualitative grip level. Possible values: low, medium, medium-high, high. Example: medium-high.", "SafetyRatingScore": "REAL. Composite safety score (0.0–100.0). Example: 92.5.", "medicalCenterGrade": "TEXT. Medical facility capability level. Possible values: Level 1 trauma, Level 2 trauma. Example: Level 1 trauma.", "MarshalPosts": "BIGINT. Number of marshal posts. Example: 40."}, "OpsEnvPack": {"timeZone": "TEXT. Local time zone indicator (human-readable, not TZ database). Example: UTC+3.", "HasNightLighting": "BOOLEAN. Whether the circuit has full-night racing lighting installed. Example: true.", "LOCAL_NOISE_LIMIT_DB": "REAL. Local regulatory noise limit in dB. Example: 105.0.", "SustainabilityCert": "TEXT. Sustainability certification held by the venue. Possible values (observed): ISO 20121, LEED. **NULL means no certification on record or assessment not completed.** Example: LEED.", "Fire_Suppression_Type": "TEXT. Primary fire suppression systems. Possible values: foam, foam + water mist, CO2. Example: foam + water mist.", "EvacuationRoutes": "TEXT. Summary of main evacuation gate directions. Example: N, W gates."}, "MediaHospPack": {"TV_Compound_Capacity": "BIGINT. Approximate media/TV compound vehicle bay capacity. Example: 40.", "MediaCenterSeats": "BIGINT. Number of media center seats. Example: 400.", "Hospitality_Suites": "BIGINT. Count of hospitality suites. Example: 50.", "parking_spaces_total": "BIGINT. Total on-site parking spaces for spectators and staff. Example: 15000.", "EmergencyHeliPads": "BIGINT. Number of emergency helicopter pads. Example: 1."}}';
COMMENT ON COLUMN "circuit_facilities"."venue_infrastructure_matrix" IS 'JSONB column. Groups venue infrastructure, resilience, security, spectator amenities, mobility/logistics, environmental safeguards, and admin notes/meta.  Nested fields: {"PowerComms": {"PowerGridCapacity_MW": "REAL. Available grid power capacity in megawatts. Example: 12.5.", "BackupGenerators": "BIGINT. Count of backup generator units. Example: 8.", "backupFuelAutonomy_hr": "BIGINT. Hours of fuel autonomy for backup power. Example: 24.", "FiberBackbones": "BIGINT. Number of fiber backbone paths (redundant links). Example: 4.", "WiFi_APs_Installed": "BIGINT. Installed Wi-Fi access points across the venue. Example: 1200."}, "SafetySecurity": {"CCTV_cameras": "BIGINT. Deployed CCTV cameras. Example: 600.", "TURNSTILES_COUNT": "BIGINT. Number of entry turnstiles. Example: 120.", "FireHydrants": "BIGINT. Number of fire hydrants across the venue. Example: 90.", "SecurityStaffCapacity": "BIGINT. Maximum security staffing capacity. Example: 1200.", "VolunteerCapacity": "BIGINT. Maximum volunteer staffing capacity. Example: 900.", "MedicsOnSite": "BIGINT. Number of medical staff on site. Example: 80."}, "SpectatorAmenity": {"restroomBlocks": "BIGINT. Count of restroom blocks. Example: 45.", "Food_Stalls": "BIGINT. Count of food & beverage stalls. Example: 200.", "FirstAidPosts": "BIGINT. Number of first-aid posts. Example: 12.", "WaterRefillPoints": "BIGINT. Public water refill stations. Example: 60.", "BigScreensCount": "BIGINT. Number of large spectator video screens. Example: 12.", "PA_Speakers_Zones": "BIGINT. Count of PA (public address) speaker zones. Example: 18.", "GrandstandRoofCoverage": "REAL. Fraction of grandstand seating covered by roofs (0.0–1.0). Example: 0.35."}, "MobilityLogistics": {"ShuttleBusBays": "BIGINT. Count of shuttle bus bays. Example: 10.", "rideShareDropoffs": "BIGINT. Count of designated rideshare drop-off points. Example: 6.", "VIP_DROPOFFS": "BIGINT. Count of VIP drop-off points. Example: 4.", "TeamTruckBays": "BIGINT. Number of paddock/team truck loading bays. Example: 20.", "FreightWarehouse_m2": "REAL. Freight warehouse area (m²). Example: 2500.0.", "Cold_Storage_m2": "REAL. Cold storage area (m²) for F&B/logistics. **NULL means not provisioned or not recorded (e.g., very few Food_Stalls).** Example: 259.1."}, "EnvResilience": {"SOLAR_KW_PEAK": "REAL. Peak installed solar capacity in kW. **NULL means no solar installation recorded or data unavailable (e.g., insufficient roof coverage).** Example: 595.8.", "WindSensors": "BIGINT. Count of installed wind sensors. Example: 8.", "Lightning_Rods": "BIGINT. Count of lightning protection rods. Example: 14.", "Flood_Barriers_M": "REAL. Typical flood barrier height in meters. Example: 1.2.", "WeatherStationPresent": "BOOLEAN. Whether a dedicated weather station is installed. Example: true."}, "OpsNotesMeta": {"notes_": "TEXT. Operational notes or follow-ups (e.g., upgrades, maintenance). **NULL means no notes captured or no outstanding actions.** Example: Install more cameras.", "META": "JSONB. Vendor/deployment metadata (e.g., {vendor:…}). **NULL means vendor metadata not recorded.** Example: {vendor: Bosch}.", "created_on": "TIMESTAMP. Row creation timestamp. Defaults to now(). Example: 2024-03-01 08:00:00."}}';
COMMENT ON COLUMN "driver_profiles"."driver_brand_presence_kit" IS 'JSONB column. Collects public-facing/brand, representation, gear, rights/policy, comms reputation, languages/licenses, and audit stamp for a driver.  Nested fields: {"Representation": {"ManagerName": "TEXT. Name of the driver’s personal manager. **NULL means the driver is self-managed or manager data is not provided.** Example: Manager X.", "AgentCompany": "TEXT. Agency or representation company of the driver. **NULL means the driver does not have agency representation.** Example: CAA."}, "GearPack": {"HelmetBrand": "TEXT. Brand of racing helmet used. Possible values: Bell, Arai, Schuberth. Example: Bell.", "SUIT_BRAND": "TEXT. Brand of racing suit used. Possible values: Alpinestars, OMP, Sparco. Example: Alpinestars.", "ShoeBrand": "TEXT. Brand of racing shoes used. Possible values: Puma, Nike, Adidas. Example: Puma.", "SimRigBrand": "TEXT. Simulator rig brand used for practice. Possible values: Fanatec, Simucube, Logitech. Example: Fanatec.", "simHours_Week": "REAL. Average number of simulation training hours per week. Example: 6.5."}, "PublicFacing": {"MerchStoreURL": "TEXT. URL of the official driver merchandise store. **NULL means the driver has no merchandise store.** Example: http://store.example.com/2.", "PersonalSiteUrl": "TEXT. Driver’s official personal website URL. Example: http://driver2.com.", "Instagram_Handle": "TEXT. Driver’s Instagram handle. Example: @racer2_official.", "Twitter_Handle": "TEXT. Driver’s Twitter/X handle. Example: @Racer2.", "TikTok_Handle": "TEXT. Driver’s TikTok handle. Example: @racer2speed.", "YOUTUBE_Handle": "TEXT. Driver’s YouTube handle. Example: @racer2YT.", "Twitch_Handle": "TEXT. Driver’s Twitch handle. Example: @racer2_streams."}, "RightsPolicy": {"PR_Restrictions": "TEXT. Public relations restrictions. Example: No ambush marketing.", "DataRightsScope": "TEXT. Data rights access scope. Example: Telemetry excerpt only.", "ImageRightsScope": "TEXT. Image rights scope. Example: Non-exclusive."}, "CommsReputation": {"PressRating_1_10": "REAL. Media press-friendliness rating (1–10). Example: 8.7.", "FanSentiment_1_10": "REAL. Fan sentiment rating (1–10). Example: 9.1.", "Public_Speaking": "TEXT. Public speaking skill level. Possible values: basic, intermediate, advanced. Example: advanced.", "CharityAffiliation": "TEXT. Charity or foundation affiliation. **NULL means no charity affiliation is recorded.** Example: STEM Foundation.", "Notes_": "TEXT. Additional notes on preferences or requirements. **NULL means no notes were recorded.** Example: Prefers neutral colors."}, "LangLicenses": {"LANGUAGES_JSON": "JSONB. Languages spoken by the driver, keyed by ISO codes. Example: {en:true,es:true}.", "licensesJSON": "JSONB. Licenses held by the driver. Example: {FIA Super Licence:true}."}, "AuditStamp": {"Last_Updated": "TIMESTAMP. Last update timestamp. Example: 2024-02-01."}}';
COMMENT ON COLUMN "innovation_technologies"."tech_lifecycle_dossier" IS 'JSONB column. Captures performance deltas, materials/suppliers, testing usage, costs, homologation/regulatory, approvals, documentation, ownership signals, timing, and risk notes across a technology’s lifecycle.  Nested fields: {"PerformanceBlock": {"ExpectedGain_sec": "REAL. Expected performance gain in seconds. **NULL means no expected gain has been calculated.** Example: 0.150.", "WeightDeltaKG": "REAL. Weight change associated with the technology, in kilograms. Example: -1.2.", "Performance_JSON": "JSONB. Performance data or expected improvements for the technology. Example: {delta:-0.18}.", "CostCapImpact_MUSD": "REAL. Impact of the technology on the cost cap in millions of USD. **NULL means the impact is not yet defined.** Example: 0.8."}, "Materials_Suppliers": {"MaterialSpec": "TEXT. Material specification used for the technology. Example: CF prepreg T800.", "SUPPLIER": "TEXT. Supplier of materials or services for the technology. **NULL means no supplier has been assigned or disclosed.** Example: Hexcel.", "PatentRef": "TEXT. Reference number for any patent related to the technology. Example: US-123456."}, "Testing_Usage": {"WindTunnelHours": "REAL. Number of wind tunnel hours dedicated to the technology. Example: 12.0.", "CFD_Core_Hours": "REAL. Number of computational fluid dynamics (CFD) hours for the technology. Example: 50000.0.", "TestsCompleted": "BIGINT. Number of tests completed for the technology. **NULL means no tests have been completed yet.** Example: 35.", "TESTS_PLANNED": "BIGINT. Number of tests planned for the technology. Example: 12."}, "Homologation_Reg": {"HomologationNeeded": "BOOLEAN. Whether homologation (official approval) is required for the technology. Example: true.", "HomologationWindow": "TEXT. Window during which homologation is expected to occur. Example: pre-season.", "RegulatoryRiskScore": "REAL. Risk score for regulatory approval (0.0–1.0). Example: 0.4.", "FailureMode_JSON": "JSONB. JSON object outlining potential failure modes of the technology. Example: {flutter:high}.", "RiskNotes": "TEXT. Notes on any risk factors for the technology. Example: vibration near T8."}, "Compliance_Approvals": {"ApprovalsJson": "JSONB. Approval statuses for the technology. Example: {FIA:pending}.", "DOC_LINK": "TEXT. URL linking to official documentation for the technology. Example: http://... ."}, "Timing_Admin": {"RETIRE_DATE": "DATE. Date when the technology is expected to be retired. Example: 2025-07-01.", "LeadEngineer": "TEXT. Name of the lead engineer overseeing the technology. Example: E. Smith."}}';
COMMENT ON COLUMN "race_incidents"."incident_stewarding_outcome" IS 'JSONB column. Combines flags, stewarding decisions/penalties, impact/cost metrics, medical/pit requirements, contextual conditions, and reference media/telemetry for each incident.  Nested fields: {"FlagPack": {"YellowFlag": "BOOLEAN. Whether a yellow flag was deployed due to the incident. Example: true.", "VSC_Deployed": "BOOLEAN. Whether a Virtual Safety Car (VSC) was deployed. Example: false.", "SC_DEPLOYED": "BOOLEAN. Whether a Safety Car was deployed. Example: true.", "RED_FLAG": "BOOLEAN. Whether a red flag was deployed. Example: false."}, "Stewarding": {"StewardInvestigation": "BOOLEAN. Whether the incident was investigated by the stewards. Example: true.", "StewardOutcome": "TEXT. Outcome of the steward''s investigation. Possible values: No further action, Penalty, Warning. Example: No further action.", "PenaltyPoints": "BIGINT. Penalty points assigned. **NULL means no penalty points were assigned.** Example: 2.", "GridPenaltyPlaces": "BIGINT. Grid penalty places imposed due to the incident. **NULL means no grid penalty was imposed.** Example: 3.", "TimePenalty_sec": "REAL. Time penalty in seconds imposed due to the incident. **NULL means no time penalty was assigned.** Example: 5.0."}, "ImpactCost": {"Severity_Score": "REAL. Severity score of the incident (0.0–1.0). Example: 0.5.", "DebrisField_m": "REAL. Length of the debris field in meters. Example: 35.0.", "DeltaRaceTime_ms": "BIGINT. Time lost during the incident in milliseconds. Example: 120000.", "CarDamageCost_MUSD": "REAL. Cost of car damage in millions of USD. Example: 0.35."}, "MedicalPitReqs": {"PitVisitRequired": "BOOLEAN. Whether a pit stop is required due to the incident. Example: true.", "MedicalCheckRequired": "BOOLEAN. Whether a medical check is required for the driver involved. Example: false."}, "ContextConditions": {"Weather_Snapshot": "TEXT. Weather snapshot during the incident. Example: light rain.", "TyreCompound": "TEXT. Tyre compound used during the incident. Example: C3.", "TyreAge_Laps": "BIGINT. Age of the tyre in laps at the time of the incident. Example: 12.", "FuelLoad_KG": "REAL. Fuel load in kilograms at the time of the incident. Example: 45.0.", "ERS_State_pct": "REAL. ERS (Energy Recovery System) state as a percentage at the time of the incident. Example: 0.65."}, "Refs": {"VideoRef": "TEXT. Reference to the video footage of the incident. Example: CAM-T8-04.", "TelemetryRef": "TEXT. Reference for the telemetry data associated with the incident. Example: INC123."}}';
COMMENT ON COLUMN "driver_biometric_metrics"."driver_brand_presence_kit" IS 'TODO: 请为 driver_brand_presence_kit 添加描述。';
COMMENT ON COLUMN "cartelemetrysnapshot"."telemetry_id" IS 'BIGINT. Primary key. Unique telemetry snapshot identifier';
COMMENT ON COLUMN "cartelemetrysnapshot"."race_ref" IS 'BIGINT. Foreign key referencing races(rak_id). Related race';
COMMENT ON COLUMN "cartelemetrysnapshot"."driver_ref" IS 'BIGINT. Foreign key referencing drivers(drv_main). Related driver';
COMMENT ON COLUMN "cartelemetrysnapshot"."lap_number" IS 'BIGINT. Lap number during which snapshot was taken';
COMMENT ON COLUMN "cartelemetrysnapshot"."track_position_m" IS 'REAL. Position on track in meters from start/finish Typical range: 0 to 7000.';
COMMENT ON COLUMN "cartelemetrysnapshot"."speed_kph" IS 'REAL. Car speed in km/h Typical range: 0 to 370.';
COMMENT ON COLUMN "cartelemetrysnapshot"."rpm" IS 'BIGINT. Engine RPM';
COMMENT ON COLUMN "cartelemetrysnapshot"."gear" IS 'BIGINT. Current gear';
COMMENT ON COLUMN "cartelemetrysnapshot"."throttle_pct" IS 'REAL. Throttle position percentage Typical range: 0 to 100.';
COMMENT ON COLUMN "cartelemetrysnapshot"."brake_pct" IS 'REAL. Brake pressure percentage Typical range: 0 to 100.';
COMMENT ON COLUMN "cartelemetrysnapshot"."steering_angle_deg" IS 'REAL. Steering wheel angle in degrees Typical range: -180 to 180.';
COMMENT ON COLUMN "cartelemetrysnapshot"."lateral_g" IS 'REAL. Lateral G-force Typical range: -6 to 6.';
COMMENT ON COLUMN "cartelemetrysnapshot"."longitudinal_g" IS 'REAL. Longitudinal G-force Typical range: -5 to 5.';
COMMENT ON COLUMN "cartelemetrysnapshot"."drs_open" IS 'REAL. DRS flap status (0=closed, 1=open) Typical range: 0 to 1.';
COMMENT ON COLUMN "cartelemetrysnapshot"."ers_deploy_kj" IS 'REAL. ERS energy deployed in kJ Typical range: 0 to 4000.';
COMMENT ON COLUMN "cartelemetrysnapshot"."ers_harvest_kj" IS 'REAL. ERS energy harvested in kJ Typical range: 0 to 4000.';
COMMENT ON COLUMN "cartelemetrysnapshot"."fuel_remaining_kg" IS 'REAL. Fuel remaining in kg Typical range: 0 to 110.';
COMMENT ON COLUMN "cartelemetrysnapshot"."water_temp_c" IS 'REAL. Engine water temperature in Celsius Typical range: 80 to 130.';
COMMENT ON COLUMN "cartelemetrysnapshot"."oil_temp_c" IS 'REAL. Engine oil temperature in Celsius Typical range: 80 to 160.';
COMMENT ON COLUMN "cartelemetrysnapshot"."oil_pressure_bar" IS 'REAL. Oil pressure in bar Typical range: 2 to 7.';
COMMENT ON COLUMN "cartelemetrysnapshot"."captured_at" IS 'TIMESTAMP WITHOUT TIME ZONE. Timestamp when telemetry was captured';
COMMENT ON COLUMN "cartelemetrysnapshot"."sensor_flags" IS 'JSONB. Sensor status flags';
COMMENT ON COLUMN "sensorconfiguration"."sensor_config_id" IS 'BIGINT. Primary key. Unique sensor configuration identifier';
COMMENT ON COLUMN "sensorconfiguration"."constructor_ref" IS 'BIGINT. Foreign key referencing constructors(cstr_key). Related constructor';
COMMENT ON COLUMN "sensorconfiguration"."sensor_code" IS 'TEXT. Sensor reference code';
COMMENT ON COLUMN "sensorconfiguration"."sensor_name" IS 'TEXT. Sensor name Possible values: GPS Antenna, IMU Module, Wheel Speed Sensor, Brake Temp Sensor, Tire Pressure Sensor, Fuel Flow Meter, Oil Pressure Sensor, Air Speed Pitot.';
COMMENT ON COLUMN "sensorconfiguration"."sensor_type" IS 'TEXT. Type of sensor Possible values: Position, Motion, Temperature, Pressure, Speed, Force, Flow, Electrical.';
COMMENT ON COLUMN "sensorconfiguration"."manufacturer" IS 'TEXT. Sensor manufacturer Possible values: McLaren Applied, Bosch, Kistler, Honeywell, Sensata, TDK.';
COMMENT ON COLUMN "sensorconfiguration"."firmware_version" IS 'TEXT. Sensor firmware version';
COMMENT ON COLUMN "sensorconfiguration"."sampling_rate_hz" IS 'REAL. Sampling rate in Hz Typical range: 1 to 1000.';
COMMENT ON COLUMN "sensorconfiguration"."accuracy_pct" IS 'REAL. Measurement accuracy percentage Typical range: 95 to 100.';
COMMENT ON COLUMN "sensorconfiguration"."operating_temp_min_c" IS 'REAL. Minimum operating temperature Typical range: -40 to 10.';
COMMENT ON COLUMN "sensorconfiguration"."operating_temp_max_c" IS 'REAL. Maximum operating temperature Typical range: 80 to 300.';
COMMENT ON COLUMN "sensorconfiguration"."mounting_position" IS 'TEXT. Where sensor is mounted on car Possible values: Engine, Gearbox, Suspension, Wheel, Aero, Cockpit, Floor, Wing.';
COMMENT ON COLUMN "sensorconfiguration"."weight_grams" IS 'REAL. Sensor weight in grams Typical range: 5 to 500.';
COMMENT ON COLUMN "sensorconfiguration"."calibration_date" IS 'DATE. Last calibration date';
COMMENT ON COLUMN "sensorconfiguration"."calibration_interval_days" IS 'BIGINT. Required calibration interval';
COMMENT ON COLUMN "sensorconfiguration"."status" IS 'TEXT. Sensor status Possible values: Active, Spare, Faulty, Retired.';
COMMENT ON COLUMN "sensorconfiguration"."unit_cost_usd" IS 'REAL. Cost per unit Typical range: 50 to 50000.';
COMMENT ON COLUMN "sensorconfiguration"."stock_count" IS 'BIGINT. Number in stock';
COMMENT ON COLUMN "sensorconfiguration"."created_at" IS 'TIMESTAMP WITHOUT TIME ZONE. Record creation timestamp';
COMMENT ON COLUMN "tiretelemetry"."tire_tel_id" IS 'BIGINT. Primary key. Unique tire telemetry identifier';
COMMENT ON COLUMN "tiretelemetry"."telemetry_ref" IS 'BIGINT. Foreign key referencing CarTelemetrySnapshot(TELEMETRY_ID). Related telemetry snapshot';
COMMENT ON COLUMN "tiretelemetry"."tire_position" IS 'TEXT. Tire position on car Possible values: FL, FR, RL, RR.';
COMMENT ON COLUMN "tiretelemetry"."compound" IS 'TEXT. Tire compound type Possible values: Soft, Medium, Hard, Intermediate, Wet.';
COMMENT ON COLUMN "tiretelemetry"."tire_age_laps" IS 'BIGINT. Tire age in laps';
COMMENT ON COLUMN "tiretelemetry"."surface_temp_c" IS 'REAL. Tire surface temperature in Celsius Typical range: 40 to 140.';
COMMENT ON COLUMN "tiretelemetry"."inner_temp_c" IS 'REAL. Tire inner temperature Typical range: 50 to 140.';
COMMENT ON COLUMN "tiretelemetry"."core_temp_c" IS 'REAL. Tire core temperature Typical range: 45 to 130.';
COMMENT ON COLUMN "tiretelemetry"."pressure_psi" IS 'REAL. Tire pressure in PSI Typical range: 17 to 27.';
COMMENT ON COLUMN "tiretelemetry"."wear_pct" IS 'REAL. Tire wear percentage (0=new, 100=worn) Typical range: 0 to 100.';
COMMENT ON COLUMN "tiretelemetry"."degradation_rate" IS 'REAL. Degradation rate per lap (seconds) Typical range: 0 to 0.3.';
COMMENT ON COLUMN "tiretelemetry"."graining" IS 'BOOLEAN. Whether graining is detected Boolean flag (true/false).';
COMMENT ON COLUMN "tiretelemetry"."blistering" IS 'BOOLEAN. Whether blistering is detected Boolean flag (true/false).';
COMMENT ON COLUMN "tiretelemetry"."lateral_grip_coefficient" IS 'REAL. Lateral grip coefficient Typical range: 0.5 to 2.5.';
COMMENT ON COLUMN "tiretelemetry"."longitudinal_grip" IS 'REAL. Longitudinal grip coefficient Typical range: 0.5 to 2.5.';
COMMENT ON COLUMN "tiretelemetry"."vibration_frequency_hz" IS 'REAL. Vibration frequency in Hz Typical range: 0 to 200.';
COMMENT ON COLUMN "tiretelemetry"."camber_deg" IS 'REAL. Tire camber angle in degrees Typical range: -5 to 0.';
COMMENT ON COLUMN "tiretelemetry"."toe_deg" IS 'REAL. Tire toe angle in degrees Typical range: -0.5 to 0.5.';
COMMENT ON COLUMN "tiretelemetry"."flat_spot" IS 'BOOLEAN. Whether flat spot is detected Boolean flag (true/false).';
COMMENT ON COLUMN "tiretelemetry"."rolling_circumference_mm" IS 'REAL. Rolling circumference in mm Typical range: 1900 to 2050.';
COMMENT ON COLUMN "tiretelemetry"."captured_at" IS 'TIMESTAMP WITHOUT TIME ZONE. Timestamp when captured';
COMMENT ON COLUMN "enginetelemetry"."engine_tel_id" IS 'BIGINT. Primary key. Unique engine telemetry identifier';
COMMENT ON COLUMN "enginetelemetry"."telemetry_ref" IS 'BIGINT. Foreign key referencing CarTelemetrySnapshot(TELEMETRY_ID). Related telemetry snapshot';
COMMENT ON COLUMN "enginetelemetry"."rpm" IS 'BIGINT. Engine RPM';
COMMENT ON COLUMN "enginetelemetry"."power_kw" IS 'REAL. Power output in kilowatts Typical range: 0 to 750.';
COMMENT ON COLUMN "enginetelemetry"."torque_nm" IS 'REAL. Torque in Newton-meters Typical range: 0 to 600.';
COMMENT ON COLUMN "enginetelemetry"."fuel_flow_kg_per_hr" IS 'REAL. Fuel flow rate in kg/hour Typical range: 0 to 100.';
COMMENT ON COLUMN "enginetelemetry"."intake_air_temp_c" IS 'REAL. Intake air temperature Typical range: 10 to 60.';
COMMENT ON COLUMN "enginetelemetry"."exhaust_temp_c" IS 'REAL. Exhaust gas temperature Typical range: 500 to 1050.';
COMMENT ON COLUMN "enginetelemetry"."turbo_boost_bar" IS 'REAL. Turbocharger boost pressure in bar Typical range: 0 to 5.';
COMMENT ON COLUMN "enginetelemetry"."mgu_k_power_kw" IS 'REAL. MGU-K power output in kW Typical range: -120 to 120.';
COMMENT ON COLUMN "enginetelemetry"."mgu_h_power_kw" IS 'REAL. MGU-H power output in kW Typical range: -100 to 100.';
COMMENT ON COLUMN "enginetelemetry"."battery_soc_pct" IS 'REAL. Battery state of charge percentage Typical range: 0 to 100.';
COMMENT ON COLUMN "enginetelemetry"."battery_temp_c" IS 'REAL. Battery temperature Typical range: 20 to 70.';
COMMENT ON COLUMN "enginetelemetry"."coolant_flow_lpm" IS 'REAL. Coolant flow rate in liters per minute Typical range: 30 to 150.';
COMMENT ON COLUMN "enginetelemetry"."oil_scavenge_temp_c" IS 'REAL. Oil scavenge temperature Typical range: 80 to 170.';
COMMENT ON COLUMN "enginetelemetry"."engine_mode" IS 'TEXT. Current engine mode Possible values: Race, Qualifying, Overtake, Fuel Save, Cool Down.';
COMMENT ON COLUMN "enginetelemetry"."knock_detected" IS 'BOOLEAN. Whether engine knock is detected Boolean flag (true/false).';
COMMENT ON COLUMN "enginetelemetry"."vibration_level_g" IS 'REAL. Engine vibration level in g Typical range: 0 to 3.';
COMMENT ON COLUMN "enginetelemetry"."limp_mode" IS 'BOOLEAN. Whether engine is in limp/safe mode Boolean flag (true/false).';
COMMENT ON COLUMN "enginetelemetry"."lambda_value" IS 'REAL. Air-fuel ratio lambda value Typical range: 0.8 to 1.2.';
COMMENT ON COLUMN "enginetelemetry"."captured_at" IS 'TIMESTAMP WITHOUT TIME ZONE. Timestamp when captured';
COMMENT ON COLUMN "telemetryanomalylog"."anomaly_id" IS 'BIGINT. Primary key. Unique anomaly log identifier';
COMMENT ON COLUMN "telemetryanomalylog"."telemetry_ref" IS 'BIGINT. Foreign key referencing CarTelemetrySnapshot(TELEMETRY_ID). Related telemetry snapshot';
COMMENT ON COLUMN "telemetryanomalylog"."anomaly_type" IS 'TEXT. Type of anomaly detected Possible values: Over-temperature, Under-pressure, Sensor Failure, Vibration Alert, Power Loss, Electrical Fault, Hydraulic Warning, Brake Wear.';
COMMENT ON COLUMN "telemetryanomalylog"."severity" IS 'TEXT. Anomaly severity level Possible values: Critical, Warning, Info.';
COMMENT ON COLUMN "telemetryanomalylog"."system_affected" IS 'TEXT. System where anomaly was detected Possible values: Engine, Gearbox, ERS, Suspension, Brakes, Aero, Cooling, Hydraulics.';
COMMENT ON COLUMN "telemetryanomalylog"."detected_at" IS 'TIMESTAMP WITHOUT TIME ZONE. When anomaly was detected';
COMMENT ON COLUMN "telemetryanomalylog"."resolved_at" IS 'TIMESTAMP WITHOUT TIME ZONE. When anomaly was resolved **NULL means Anomaly not yet resolved.**';
COMMENT ON COLUMN "telemetryanomalylog"."threshold_value" IS 'REAL. Expected threshold value Typical range: 0 to 500.';
COMMENT ON COLUMN "telemetryanomalylog"."actual_value" IS 'REAL. Actual measured value triggering the anomaly Typical range: 0 to 600.';
COMMENT ON COLUMN "telemetryanomalylog"."deviation_pct" IS 'REAL. Deviation from threshold (%) Typical range: 0.1 to 100.';
