COMMENT ON COLUMN "regulatorycompliancelog"."compliance_category" IS 'TEXT. Category of compliance requirement Possible values: Technical, Sporting, Financial, Safety, Environmental, Anti-Doping.';
COMMENT ON COLUMN "regulatorycompliancelog"."regulation_reference" IS 'TEXT. Official regulation reference number';
COMMENT ON COLUMN "regulatorycompliancelog"."effective_date" IS 'DATE. Date regulation takes effect';
COMMENT ON COLUMN "regulatorycompliancelog"."audit_date" IS 'DATE. Date of compliance audit';
COMMENT ON COLUMN "regulatorycompliancelog"."compliance_status" IS 'TEXT. Current compliance status Possible values: Compliant, Non-Compliant, Under Review, Exempted, Pending.';
COMMENT ON COLUMN "regulatorycompliancelog"."penalty_amount_usd" IS 'REAL. Penalty amount if non-compliant Typical range: 0 to 1000000. **NULL means No penalty assessed.**';
COMMENT ON COLUMN "regulatorycompliancelog"."corrective_action" IS 'TEXT. [''Design Modification'', ''Process Change'', ''Training Required'', ''Equipment Replacement'', ''Documentation Update'', ''No Action Required'']';
COMMENT ON COLUMN "regulatorycompliancelog"."appeals_filed" IS 'BOOLEAN. Whether an appeal has been filed Boolean flag (true/false).';
COMMENT ON COLUMN "regulatorycompliancelog"."created_at" IS 'TIMESTAMP WITHOUT TIME ZONE. Record creation timestamp';
